     1→/**
     2→ * DeckCanvas - deck.gl-based canvas for semantic zoom visualization
     3→ *
     4→ * Replaces InfiniteCanvas (R3F-based) with deck.gl for:
     5→ * - Native semantic zoom via CompositeLayer
     6→ * - Built-in aggregation layers for heatmaps
     7→ * - OrthographicView for non-geo timeline visualization
     8→ * - Better bundle size and performance
     9→ *
    10→ * DECK-MIGRATE-001: Foundation component
    11→ * DECK-MIGRATE-002: Layer implementations with LOD
    12→ */
    13→
    14→import { useState, useCallback, useEffect, useRef, useMemo } from 'react';
    15→import DeckGL from '@deck.gl/react';
    16→import { OrthographicView } from '@deck.gl/core';
    17→import type { PickingInfo } from '@deck.gl/core';
    18→import type { Layer } from '@deck.gl/core';
    19→import type { LODLevel } from '../data/types';
    20→import { DEFAULT_VIEW_CONFIG, calculateWorldBounds } from '../data/types';
    21→import { getRenderData } from '../data/generator';
    22→import { useCanvasSelector, canvasStore, canvasActions } from '../state';
    23→import {
    24→  createMacroLayers,
    25→  createMesoLayers,
    26→  createMicroLayers,
    27→} from './layers';
    28→import { useCanvasGestures } from './hooks/useCanvasGestures';
    29→import { initializeSpatialIndex } from './spatial';
    30→
    31→// ─────────────────────────────────────────────────────────────
    32→// EXPORTED TYPES (matching InfiniteCanvas)
    33→// ─────────────────────────────────────────────────────────────
    34→
    35→/**
    36→ * Viewport information passed to parent component
    37→ */
    38→export interface ViewportInfo {
    39→  /** Y coordinate of the TOP of the viewport in world space */
    40→  topY: number;
    41→  /** Left edge of the viewport in world X coordinates */
    42→  leftX: number;
    43→  /** Right edge of the viewport in world X coordinates */
    44→  rightX: number;
    45→}
    46→
    47→/**
    48→ * Navigation target for programmatic navigation
    49→ * Can specify trainIndex, dayOffset, or both
    50→ */
    51→export interface NavigationTarget {
    52→  /** Train index (0-based) to center on vertically */
    53→  trainIndex?: number;
    54→  /** Day offset from start date to center on horizontally */
    55→  dayOffset?: number;
    56→  /** Optional zoom level to set (defaults to current zoom) */
    57→  zoom?: number;
    58→}
    59→
    60→// ─────────────────────────────────────────────────────────────
    61→// PROPS INTERFACE (matching InfiniteCanvas)
    62→// ─────────────────────────────────────────────────────────────
    63→
    64→export interface DeckCanvasProps {
    65→  zoom: number;
    66→  lod: LODLevel;
    67→  onZoomChange: (zoom: number) => void;
    68→  onViewportChange?: (viewport: ViewportInfo) => void;
    69→  onMinZoomChange?: (minZoom: number) => void;
    70→  animatedZoomTarget?: number | null;
    71→  onAnimatedZoomComplete?: () => void;
    72→  navigationTarget?: NavigationTarget | null;
    73→  onNavigationComplete?: () => void;
    74→  perfVisible?: boolean;
    75→  perfEvent?: string;
    76→}
    77→
    78→// ─────────────────────────────────────────────────────────────
    79→// CONSTANTS
    80→// ─────────────────────────────────────────────────────────────
    81→
    82→const { pxPerDay, pxPerTrain, maxZoom: configMaxZoom, lodThresholds } = DEFAULT_VIEW_CONFIG;
    83→
    84→// Animation constants
    85→const ZOOM_ANIMATION_DURATION = 250; // ms
    86→const NAVIGATION_ANIMATION_DURATION = 300; // ms
    87→
    88→// Data constants
    89→const TRAIN_COUNT = 50;
    90→const TOTAL_YEARS = 10;
    91→const TOTAL_DAYS = TOTAL_YEARS * 365;
    92→
    93→// LOD transition constants (hysteresis to prevent flickering)
    94→const LOD_HYSTERESIS = 0.15; // 15% overlap zone for crossfade
    95→
    96→// ─────────────────────────────────────────────────────────────
    97→// ZOOM CONVERSIONS
    98→// deck.gl uses log2 scale: zoom 0 = 1x, zoom 1 = 2x, zoom -1 = 0.5x
    99→// ─────────────────────────────────────────────────────────────
   100→
   101→function linearToDeckZoom(linearZoom: number): number {
   102→  return Math.log2(linearZoom);
   103→}
   104→
   105→function deckToLinearZoom(deckZoom: number): number {
   106→  return Math.pow(2, deckZoom);
   107→}
   108→
   109→// ─────────────────────────────────────────────────────────────
   110→// DECK.GL VIEW STATE TYPE
   111→// ─────────────────────────────────────────────────────────────
   112→
   113→interface DeckViewState {
   114→  target: [number, number];
   115→  zoom: number;
   116→  minZoom: number;
   117→  maxZoom: number;
   118→}
   119→
   120→// ─────────────────────────────────────────────────────────────
   121→// COMPONENT
   122→// ─────────────────────────────────────────────────────────────
   123→
   124→/**
   125→ * DeckCanvas Component
   126→ *
   127→ * Main deck.gl canvas with OrthographicView for timeline visualization.
   128→ * Compatible interface with InfiniteCanvas for seamless migration.
   129→ */
   130→export function DeckCanvas({
   131→  zoom,
   132→  lod: _lod,
   133→  onZoomChange,
   134→  onViewportChange,
   135→  onMinZoomChange,
   136→  animatedZoomTarget,
   137→  onAnimatedZoomComplete,
   138→  navigationTarget,
   139→  onNavigationComplete,
   140→  perfVisible: _perfVisible,
   141→  perfEvent: _perfEvent,
   142→}: DeckCanvasProps) {
   143→  // Container ref for size tracking
   144→  const containerRef = useRef<HTMLDivElement>(null);
   145→  const [containerSize, setContainerSize] = useState({ width: 800, height: 600 });
   146→
   147→  // Get render data and initialize spatial index
   148→  const { tasks, spatialIndex } = useMemo(() => {
   149→    const data = getRenderData();
   150→    // Initialize spatial index for O(log n) viewport queries
   151→    const index = initializeSpatialIndex(data.tasks);
   152→    return { tasks: data.tasks, spatialIndex: index };
   153→  }, []);
   154→
   155→  // Calculate world bounds (trainCount, totalDays)
   156→  const worldBounds = useMemo(
   157→    () => calculateWorldBounds(TRAIN_COUNT, TOTAL_DAYS),
   158→    []
   159→  );
   160→
   161→  // Calculate effective minimum zoom based on canvas size
   162→  const effectiveMinZoom = useMemo(() => {
   163→    const worldWidth = worldBounds.maxX - worldBounds.minX;
   164→    const worldHeight = Math.abs(worldBounds.maxY - worldBounds.minY);
   165→    const zoomToFitWidth = containerSize.width / worldWidth;
   166→    const zoomToFitHeight = containerSize.height / worldHeight;
   167→    return Math.max(0.05, Math.min(zoomToFitWidth, zoomToFitHeight) * 0.9);
   168→  }, [worldBounds, containerSize]);
   169→
   170→  // Report effective min zoom to parent
   171→  useEffect(() => {
   172→    onMinZoomChange?.(effectiveMinZoom);
   173→  }, [effectiveMinZoom, onMinZoomChange]);
   174→
   175→  // Initialize deck.gl view state from props
   176→  const [viewState, setViewState] = useState<DeckViewState>(() => ({
   177→    target: [worldBounds.maxX / 4, worldBounds.minY / 4], // Start near top-left
   178→    zoom: linearToDeckZoom(zoom),
   179→    minZoom: linearToDeckZoom(effectiveMinZoom),
   180→    maxZoom: linearToDeckZoom(configMaxZoom),
   181→  }));
   182→
   183→  // Sync external zoom changes to internal view state
   184→  useEffect(() => {
   185→    const newDeckZoom = linearToDeckZoom(zoom);
   186→    if (Math.abs(viewState.zoom - newDeckZoom) > 0.01) {
   187→      setViewState(prev => ({
   188→        ...prev,
   189→        zoom: newDeckZoom,
   190→      }));
   191→    }
   192→  }, [zoom]);
   193→
   194→  // Update min zoom when effective min changes
   195→  useEffect(() => {
   196→    setViewState(prev => ({
   197→      ...prev,
   198→      minZoom: linearToDeckZoom(effectiveMinZoom),
   199→    }));
   200→  }, [effectiveMinZoom]);
   201→
   202→  // Handle animated zoom target
   203→  useEffect(() => {
   204→    if (animatedZoomTarget != null) {
   205→      const targetDeckZoom = linearToDeckZoom(animatedZoomTarget);
   206→      setViewState(prev => ({
   207→        ...prev,
   208→        zoom: targetDeckZoom,
   209→      }));
   210→      // Report completion after animation duration
   211→      const timeout = setTimeout(() => {
   212→        onAnimatedZoomComplete?.();
   213→      }, ZOOM_ANIMATION_DURATION);
   214→      return () => clearTimeout(timeout);
   215→    }
   216→  }, [animatedZoomTarget, onAnimatedZoomComplete]);
   217→
   218→  // Handle navigation target
   219→  useEffect(() => {
   220→    if (navigationTarget) {
   221→      const newTarget: [number, number] = [...viewState.target];
   222→
   223→      if (navigationTarget.dayOffset !== undefined) {
   224→        newTarget[0] = navigationTarget.dayOffset * pxPerDay;
   225→      }
   226→      if (navigationTarget.trainIndex !== undefined) {
   227→        // Y is negative (trains go down)
   228→        newTarget[1] = -navigationTarget.trainIndex * pxPerTrain - pxPerTrain / 2;
   229→      }
   230→
   231→      setViewState(prev => ({
   232→        ...prev,
   233→        target: newTarget,
   234→        zoom: navigationTarget.zoom !== undefined
   235→          ? linearToDeckZoom(navigationTarget.zoom)
   236→          : prev.zoom,
   237→      }));
   238→
   239→      // Report completion
   240→      const timeout = setTimeout(() => {
   241→        onNavigationComplete?.();
   242→      }, NAVIGATION_ANIMATION_DURATION);
   243→      return () => clearTimeout(timeout);
   244→    }
   245→  }, [navigationTarget, onNavigationComplete]);
   246→
   247→  // Track container size with ResizeObserver
   248→  useEffect(() => {
   249→    if (!containerRef.current) return;
   250→
   251→    const observer = new ResizeObserver((entries) => {
   252→      for (const entry of entries) {
   253→        const { width, height } = entry.contentRect;
   254→        setContainerSize({ width, height });
   255→        // Also update toolkit store
   256→        canvasStore.dispatch(canvasActions.viewport.setCanvasSize({ width, height }));
   257→      }
   258→    });
   259→
   260→    observer.observe(containerRef.current);
   261→    return () => observer.disconnect();
   262→  }, []);
   263→
   264→  // Get interaction state from @mms/toolkit
   265→  const hoveredTaskId = useCanvasSelector(s => s.interaction.hoveredTaskId);
   266→  const selectedTaskId = useCanvasSelector(s => s.interaction.selectedTaskId);
   267→
   268→  // Handle view state changes from deck.gl controller
   269→  const handleViewStateChange = useCallback(
   270→    ({ viewState: newViewState }: { viewState: DeckViewState }) => {
   271→      setViewState(newViewState);
   272→
   273→      // Convert deck.gl zoom to linear and notify parent
   274→      const linearZoom = deckToLinearZoom(newViewState.zoom);
   275→      onZoomChange(linearZoom);
   276→
   277→      // Calculate viewport info for parent
   278→      const halfWidth = containerSize.width / linearZoom / 2;
   279→      const halfHeight = containerSize.height / linearZoom / 2;
   280→
   281→      const viewportInfo: ViewportInfo = {
   282→        topY: newViewState.target[1] + halfHeight, // Top edge in world Y
   283→        leftX: newViewState.target[0] - halfWidth,
   284→        rightX: newViewState.target[0] + halfWidth,
   285→      };
   286→      onViewportChange?.(viewportInfo);
   287→
   288→      // Update @mms/toolkit state for sidebar/timeline sync
   289→      canvasStore.dispatch(
   290→        canvasActions.viewport.setCamera({
   291→          x: newViewState.target[0],
   292→          y: newViewState.target[1],
   293→        })
   294→      );
   295→    },
   296→    [onZoomChange, onViewportChange, containerSize]
   297→  );
   298→
   299→  // Handle hover on tasks
   300→  const handleHover = useCallback((info: PickingInfo) => {
   301→    if (info.object && 'id' in info.object) {
   302→      canvasStore.dispatch(canvasActions.interaction.setHoveredTask(info.object.id as string));
   303→    } else {
   304→      canvasStore.dispatch(canvasActions.interaction.clearHover(null));
   305→    }
   306→  }, []);
   307→
   308→  // Handle click on tasks
   309→  const handleClick = useCallback((info: PickingInfo) => {
   310→    if (info.object && 'id' in info.object) {
   311→      const taskId = info.object.id as string;
   312→      const currentSelected = canvasStore.getState().interaction.selectedTaskId;
   313→      if (currentSelected === taskId) {
   314→        // Toggle off if clicking same task
   315→        canvasStore.dispatch(canvasActions.interaction.clearSelection(null));
   316→      } else {
   317→        canvasStore.dispatch(canvasActions.interaction.setSelectedTask(taskId));
   318→      }
   319→    } else {
   320→      // Click on background clears selection
   321→      canvasStore.dispatch(canvasActions.interaction.clearSelection(null));
   322→    }
   323→  }, []);
   324→
   325→  // ─────────────────────────────────────────────────────────────
   326→  // GESTURE HANDLING (@use-gesture/react) - DECK-COMPLETE-002
   327→  // ─────────────────────────────────────────────────────────────
   328→
   329→  // Handle zoom from gestures (pinch, wheel)
   330→  const handleGestureZoom = useCallback(
   331→    (newZoom: number, cursorX?: number, cursorY?: number) => {
   332→      const currentLinear = deckToLinearZoom(viewState.zoom);
   333→
   334→      // If cursor position provided, zoom toward that point
   335→      if (cursorX !== undefined && cursorY !== undefined) {
   336→        // Convert cursor to world coordinates
   337→        const zoomRatio = newZoom / currentLinear;
   338→
   339→        // Calculate new target to zoom toward cursor
   340→        const newTarget: [number, number] = [
   341→          viewState.target[0] + (cursorX - containerSize.width / 2) / currentLinear * (1 - 1 / zoomRatio),
   342→          viewState.target[1] + (cursorY - containerSize.height / 2) / currentLinear * (1 - 1 / zoomRatio),
   343→        ];
   344→
   345→        setViewState(prev => ({
   346→          ...prev,
   347→          target: newTarget,
   348→          zoom: linearToDeckZoom(newZoom),
   349→        }));
   350→      } else {
   351→        setViewState(prev => ({
   352→          ...prev,
   353→          zoom: linearToDeckZoom(newZoom),
   354→        }));
   355→      }
   356→      // Note: onZoomChange is called via useEffect when viewState.zoom changes
   357→    },
   358→    [viewState, containerSize]
   359→  );
   360→
   361→  // Handle pan from gestures (drag, trackpad scroll)
   362→  const handleGesturePan = useCallback(
   363→    (deltaX: number, deltaY: number) => {
   364→      const currentLinear = deckToLinearZoom(viewState.zoom);
   365→
   366→      // Convert screen delta to world delta
   367→      const worldDeltaX = deltaX / currentLinear;
   368→      const worldDeltaY = deltaY / currentLinear;
   369→
   370→      setViewState(prev => ({
   371→        ...prev,
   372→        target: [
   373→          prev.target[0] - worldDeltaX,
   374→          prev.target[1] - worldDeltaY,
   375→        ],
   376→      }));
   377→    },
   378→    [viewState.zoom]
   379→  );
   380→
   381→  // Sync viewState changes to parent and toolkit store
   382→  useEffect(() => {
   383→    const linearZoom = deckToLinearZoom(viewState.zoom);
   384→
   385→    // Notify parent of zoom change
   386→    onZoomChange(linearZoom);
   387→
   388→    // Calculate viewport info
   389→    const halfWidth = containerSize.width / linearZoom / 2;
   390→    const halfHeight = containerSize.height / linearZoom / 2;
   391→
   392→    const viewportInfo: ViewportInfo = {
   393→      topY: viewState.target[1] + halfHeight,
   394→      leftX: viewState.target[0] - halfWidth,
   395→      rightX: viewState.target[0] + halfWidth,
   396→    };
   397→    onViewportChange?.(viewportInfo);
   398→
   399→    // Update @mms/toolkit state
   400→    canvasStore.dispatch(
   401→      canvasActions.viewport.setCamera({
   402→        x: viewState.target[0],
   403→        y: viewState.target[1],
   404→      })
   405→    );
   406→  }, [viewState.target, viewState.zoom, containerSize, onZoomChange, onViewportChange]);
   407→
   408→  // Initialize gesture hook - returns bind function to spread on container
   409→  const gestureBind = useCanvasGestures(
   410→    {
   411→      onZoom: handleGestureZoom,
   412→      onPan: handleGesturePan,
   413→    },
   414→    {
   415→      zoom: deckToLinearZoom(viewState.zoom),
   416→      minZoom: effectiveMinZoom,
   417→      maxZoom: configMaxZoom,
   418→    }
   419→  );
   420→
   421→  // Calculate LOD level from zoom (for debug display)
   422→  const currentLinearZoom = deckToLinearZoom(viewState.zoom);
   423→  const lodLevel = currentLinearZoom < 0.5 ? 'MACRO' : currentLinearZoom > 2.0 ? 'MICRO' : 'MESO';
   424→
   425→  // Calculate viewport bounds for culling
   426→  const viewportBounds = useMemo(() => {
   427→    const halfWidth = containerSize.width / currentLinearZoom / 2;
   428→    const halfHeight = containerSize.height / currentLinearZoom / 2;
   429→    return {
   430→      minX: viewState.target[0] - halfWidth,
   431→      maxX: viewState.target[0] + halfWidth,
   432→      minY: viewState.target[1] - halfHeight,
   433→      maxY: viewState.target[1] + halfHeight,
   434→    };
   435→  }, [viewState.target, currentLinearZoom, containerSize]);
   436→
   437→  // Calculate LOD opacities for smooth crossfade transitions
   438→  const lodOpacities = useMemo(() => {
   439→    const z = currentLinearZoom;
   440→    const { macro: macroThreshold, micro: microThreshold } = lodThresholds;
   441→    const h = LOD_HYSTERESIS;
   442→
   443→    // Macro: Full below 0.5, fade out 0.35-0.5
   444→    const macroOpacity = z < macroThreshold - h
   445→      ? 1
   446→      : z > macroThreshold
   447→        ? 0
   448→        : 1 - (z - (macroThreshold - h)) / h;
   449→
   450→    // Micro: Full above 2.0, fade in 1.85-2.0
   451→    const microOpacity = z > microThreshold + h
   452→      ? 1
   453→      : z < microThreshold
   454→        ? 0
   455→        : (z - microThreshold) / h;
   456→
   457→    // Meso: Full in the middle, fade at boundaries
   458→    const mesoOpacity = Math.min(
   459→      z >= macroThreshold - h ? 1 : 0, // Fade in with macro fade out
   460→      z <= microThreshold + h ? 1 : 0   // Fade out with micro fade in
   461→    );
   462→
   463→    return {
   464→      macro: Math.max(0, Math.min(1, macroOpacity)),
   465→      meso: Math.max(0, Math.min(1, mesoOpacity)),
   466→      micro: Math.max(0, Math.min(1, microOpacity)),
   467→    };
   468→  }, [currentLinearZoom]);
   469→
   470→  // Create the OrthographicView
   471→  // DECK-COMPLETE-002: Disable deck.gl controller, use @use-gesture/react instead
   472→  const views = useMemo(() => new OrthographicView({
   473→    id: 'timeline',
   474→    flipY: false,
   475→    controller: {
   476→      scrollZoom: false,   // Handled by @use-gesture onWheel/onPinch
   477→      dragPan: false,      // Handled by @use-gesture onDrag
   478→      doubleClickZoom: true, // Keep for convenience
   479→      touchRotate: false,
   480→      keyboard: true,       // Keep arrow key navigation
   481→    },
   482→  }), []);
   483→
   484→  // Get focused task ID from state
   485→  const focusedTaskId = useCanvasSelector(s => s.interaction.focusedTaskId);
   486→
   487→  // DECK-COMPLETE-003: Query visible tasks using spatial index
   488→  const visibleTasks = useMemo(() => {
   489→    // For MACRO level, use all tasks (heatmap needs full data)
   490→    if (lodOpacities.macro > 0.5) {
   491→      return tasks;
   492→    }
   493→    // For MESO/MICRO, use spatial index for viewport culling
   494→    return spatialIndex.getVisibleTasks(viewportBounds, 200); // 200px overscan
   495→  }, [spatialIndex, viewportBounds, lodOpacities.macro, tasks]);
   496→
   497→  // Create layers based on LOD level with crossfade
   498→  const layers = useMemo((): Layer[] => {
   499→    const allLayers: Layer[] = [];
   500→
   501→    // MacroLayer - visible when zoom < 0.5
   502→    if (lodOpacities.macro > 0) {
   503→      allLayers.push(
   504→        ...createMacroLayers({
   505→          tasks,
   506→          trainCount: TRAIN_COUNT,
   507→          totalYears: TOTAL_YEARS,
   508→          visible: true,
   509→          opacity: lodOpacities.macro,
   510→        })
   511→      );
   512→    }
   513→
   514→    // MesoLayer - visible when 0.5 <= zoom <= 2.0
   515→    // Uses visibleTasks from spatial index for viewport culling
   516→    if (lodOpacities.meso > 0) {
   517→      allLayers.push(
   518→        ...createMesoLayers({
   519→          tasks: visibleTasks,
   520→          trainCount: TRAIN_COUNT,
   521→          totalDays: TOTAL_DAYS,
   522→          visible: true,
   523→          opacity: lodOpacities.meso,
   524→          hoveredTaskId,
   525→          selectedTaskId,
   526→          focusedTaskId,
   527→        })
   528→      );
   529→    }
   530→
   531→    // MicroLayer - visible when zoom > 2.0
   532→    // Uses visibleTasks from spatial index for viewport culling
   533→    if (lodOpacities.micro > 0) {
   534→      allLayers.push(
   535→        ...createMicroLayers({
   536→          tasks: visibleTasks,
   537→          trainCount: TRAIN_COUNT,
   538→          totalDays: TOTAL_DAYS,
   539→          visible: true,
   540→          opacity: lodOpacities.micro,
   541→          linearZoom: currentLinearZoom,
   542→          viewportBounds,
   543→          hoveredTaskId,
   544→          selectedTaskId,
   545→          focusedTaskId,
   546→        })
   547→      );
   548→    }
   549→
   550→    return allLayers;
   551→  }, [
   552→    tasks,
   553→    visibleTasks, // DECK-COMPLETE-003: Add visible tasks from spatial index
   554→    lodOpacities,
   555→    currentLinearZoom,
   556→    viewportBounds,
   557→    hoveredTaskId,
   558→    selectedTaskId,
   559→    focusedTaskId,
   560→  ]);
   561→
   562→  return (
   563→    <div
   564→      ref={containerRef}
   565→      {...gestureBind()}
   566→      style={{
   567→        width: '100%',
   568→        height: '100%',
   569→        position: 'relative',
   570→        background: '#f4f4f5', // zinc-100, matching original
   571→        touchAction: 'none', // DECK-COMPLETE-002: Required for @use-gesture
   572→      }}
   573→    >
   574→      <DeckGL
   575→        views={views}
   576→        viewState={viewState}
   577→        onViewStateChange={handleViewStateChange as any}
   578→        controller={true}
   579→        layers={layers}
   580→        onHover={handleHover}
   581→        onClick={handleClick}
   582→        width="100%"
   583→        height="100%"
   584→        style={{ position: 'absolute', top: '0', left: '0' }}
   585→        getCursor={({ isDragging, isHovering }) =>
   586→          isDragging ? 'grabbing' : isHovering ? 'pointer' : 'grab'
   587→        }
   588→      />
   589→
   590→      {/* Debug overlay - shows deck.gl status */}
   591→      <div
   592→        style={{
   593→          position: 'absolute',
   594→          bottom: 8,
   595→          right: 8,
   596→          background: 'rgba(0,0,0,0.75)',
   597→          color: '#00ff00',
   598→          padding: '6px 10px',
   599→          borderRadius: 4,
   600→          fontSize: 11,
   601→          fontFamily: 'monospace',
   602→          pointerEvents: 'none',
   603→          display: 'flex',
   604→          flexDirection: 'column',
   605→          gap: 2,
   606→        }}
   607→      >
   608→        <div>deck.gl | LOD: {lodLevel} | Zoom: {currentLinearZoom.toFixed(2)}x</div>
   609→        <div style={{ fontSize: 10, color: '#888' }}>
   610→          Target: [{viewState.target[0].toFixed(0)}, {viewState.target[1].toFixed(0)}]
   611→        </div>
   612→      </div>
   613→    </div>
   614→  );
   615→}
   616→
   617→export default DeckCanvas;
   618→

